import logging
from logging.handlers import RotatingFileHandler, TimedRotatingFileHandler

# Create a logger object with the name 'application' 
logger = logging.getLogger('Application')  
logging.basicConfig(level=logging.DEBUG) # Set log level to debug for detailed logs in production environment   

file_handler = RotatingFileHandler('/var/log/application/app.log', maxBytes=1024*1024, backupCount=3 ) 
formatter = logging.Formatter('%(asctime)s - %(name)s - %(levelname)s - %(message)s') # Define the log format  
file_handler.setFormatter(formatter)   
logger.addHandler(file_handler)